import asyncio

from solution import process_in_batches


def test_cancellation_event_stops_later_batches():
    async def _run():
        event = asyncio.Event()

        async def handler(batch):
            event.set()
            return list(batch)

        return await process_in_batches([1, 2, 3, 4], handler, batch_size=2, concurrency=1, cancel_event=event)

    assert asyncio.run(_run()) == [1, 2]
